{{
  (() => {
    const dados = _TaxaSemResposta.data;
    if (!dados || dados.length === 0) {
      return "Nenhum dado encontrado para o período.";
    }

    const hoje = dados[dados.length - 1];

    // Se não houve nenhuma conversa no dia atual
    if (hoje.total_conversas === 0) {
      return `Não houveram interações na data atual (${hoje.dia}).`;
    }

    // Caso contrário, mostra a taxa normalmente
    return `Hoje (${hoje.dia}) ${hoje.taxa_sem_resposta_percentual}% das conversas ficaram sem resposta (${hoje.sem_resposta} de ${hoje.total_conversas}).`;
  })()
}}
